+            if sensitive_context {
+                libc::EAGAIN
+            } else {
+                let mut internal_key = PthreadKey::default();
+                let rc = core_pthread_key_create(&mut internal_key, destructor);
+                if rc == 0 {
+                    // SAFETY: key is non-null and we write the index.
+                    unsafe { *key = internal_key.id };
+                }
+                rc
+            }
+        },
+        || {
+            let mut internal_key = PthreadKey::default();
+            let rc = core_pthread_key_create(&mut internal_key, destructor);
+            if rc == 0 {
+                // SAFETY: key is non-null and we write the index.
+                unsafe { *key = internal_key.id };
+            }
+            rc
+        },
+    )
